async (page) => {
  const keyFor = (axis, sign) => axis === 'x' ? (sign < 0 ? 'KeyA' : 'KeyD') : (sign < 0 ? 'KeyS' : 'KeyW');
  async function tap(key, ms = 80) {
    await page.keyboard.down(key);
    await page.waitForTimeout(ms);
    await page.keyboard.up(key);
    await page.waitForTimeout(30);
  }
  async function pos(id) {
    return await page.evaluate((entityId) => window.__THREENATIVE_RUNTIME__.entityWorldPosition(entityId), id);
  }
  async function moveTo(target) {
    for (let i = 0; i < 160; i += 1) {
      const p = await pos('player');
      const dx = target[0] - p[0];
      const dz = target[2] - p[2];
      if (dx * dx + dz * dz < 0.38 * 0.38) return { reached: true, p, i };
      if (Math.abs(dx) > 0.18) await tap(keyFor('x', dx), Math.min(120, Math.max(35, Math.abs(dx) * 120)));
      if (Math.abs(dz) > 0.18) await tap(keyFor('z', dz), Math.min(120, Math.max(35, Math.abs(dz) * 120)));
    }
    return { reached: false, p: await pos('player') };
  }
  const ids = ['pickup-1', 'pickup-2', 'pickup-3', 'pickup-4', 'pickup-5'];
  const results = [];
  for (const id of ids) {
    const target = await pos(id);
    results.push({ id, target, result: await moveTo(target), state: await page.evaluate(() => window.__THREENATIVE_RUNTIME__.resourceSnapshot('GameState')) });
  }
  await page.waitForTimeout(300);
  const wonState = await page.evaluate(() => ({
    resource: window.__THREENATIVE_RUNTIME__.resourceSnapshot('GameState'),
    score: window.__THREENATIVE_RUNTIME__.uiNodeSnapshot('score-label'),
    status: window.__THREENATIVE_RUNTIME__.uiNodeSnapshot('status-label'),
    retry: window.__THREENATIVE_RUNTIME__.uiNodeSnapshot('retry-label'),
    body: document.body.innerText
  }));
  await page.keyboard.press('KeyR');
  await page.waitForTimeout(200);
  const resetState = await page.evaluate(() => ({
    resource: window.__THREENATIVE_RUNTIME__.resourceSnapshot('GameState'),
    score: window.__THREENATIVE_RUNTIME__.uiNodeSnapshot('score-label'),
    player: window.__THREENATIVE_RUNTIME__.entityWorldPosition('player'),
    pickup1: window.__THREENATIVE_RUNTIME__.entityWorldPosition('pickup-1'),
    body: document.body.innerText
  }));
  return { results, wonState, resetState };
}
